# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

local args = ngx.req.get_uri_args()
local filename = args.filename

if not filename or filename == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: filename parameter is required")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local function normalize_path(path)
    local parts = {}
    for part in string.gmatch(path, "[^/]+") do
        if part == ".." then
            if #parts > 0 then
                table.remove(parts)
            end
        elseif part ~= "." and part ~= "" then
            table.insert(parts, part)
        end
    end
    return table.concat(parts, "/")
end

local function is_safe_path(base_dir, requested_path)
    local normalized = normalize_path(requested_path)
    
    if string.find(normalized, "%.%.", 1, true) then
        return false
    end
    
    local full_path = base_dir .. "/" .. normalized
    
    local resolved_path = io.popen("realpath -m '" .. full_path:gsub("'", "'\\''") .. "' 2>/dev/null"):read("*a")
    if resolved_path then
        resolved_path = resolved_path:gsub("%s+$", "")
    end
    
    local resolved_base = io.popen("realpath -m '" .. base_dir:gsub("'", "'\\''") .. "' 2>/dev/null"):read("*a")
    if resolved_base then
        resolved_base = resolved_base:gsub("%s+$", "")
    end
    
    if not resolved_path or not resolved_base then
        return false
    end
    
    if string.sub(resolved_path, 1, #resolved_base) ~= resolved_base then
        return false
    end
    
    if #resolved_path > #resolved_base and string.sub(resolved_path, #resolved_base + 1, #resolved_base + 1) ~= "/" then
        return false
    end
    
    return true, resolved_path
end

local base_dir = "./files"

local safe, resolved_path = is_safe_path(base_dir, filename)

if not safe then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: Access denied - invalid file path")
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

local file, err = io.open(resolved_path, "r")

if not file then
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say("Error: File not found - " .. (err or "unknown error"))
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

local content = file:read("*all")
file:close()

ngx.header.content_type = "text/plain"
ngx.say(content)